select @Detail = case when @tk_chi_tiet = 1 then 1 else 0 end
exec rs_rptAllAccountsActivity @tu_ngay, @den_ngay, @ma_dvcs, @tk_so_cai_1, @tk_1, @tk_bac_1, @Detail, @@language, @@userID, @@admin







