      /* <flatten type="Javascript"> */
function onChange$VoucherFilter$Tab(o, e) {
  var f = o.parentForm, c = f.getItemValue('tk_so_cai') ? 'tk_so_cai_1' : (f.getItemValue('tk') ? 'tk_1' : 'tk_bac_1');
  f.focusWhenTabChanged(['ma_dvcs', c]);
}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$VoucherFilter$Tab);
  f._tabContainer._loaded = true;
  changeLookupReadonly(f, 'ma_dvcs');
  if (!f.getItemValue('tk_so_cai')) f.getItem('tk_so_cai_1').disabled = true;
  if (!f.getItemValue('tk')) {
    var o = f.getItem('tk_1');
    $common.setVisible(o.a, false)
    o.disabled = true;
  }
  if (!f.getItemValue('tk_bac')) f.getItem('tk_bac_1').disabled = f.getItem('xem_tat').disabled = f.getItem('tk_chi_tiet').disabled = true;
  if (!f.getItemValue('ngay3')) f.setItemValue('ngay3', new Date());
}
function close$VoucherFilter$(sender) {
  try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
  try {f._tabContainer.remove_activeTabChanged(onChange$VoucherFilter$Tab);} catch (ex) {}
  }
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      f.grid._hiddenFields = [{Fields: 'du_dk_nt, ps_no_nt, ps_co_nt, du_ck_nt, nc_dk2, nc_ck2', Value: (f.getItemValue('mau_bc') == '10')},
        {Fields: 'nc_dk, nc_ck', Value: (f.getItemValue('mau_bc') == '20')}];
      f.grid._alterTitle = [null, [['%d1', f.getItem('tu_ngay').value, true], ['%d2', f.getItem('den_ngay').value, true]]];
      var g = f.grid, c = f.getItemValue('chon_tt');
      g._hiddenForms = [
          {Form: [0, 1, 2, 3, 4], Value: (c != '1')},
          {Form: [5, 6], Value: (c == '1')}
        ];
      g._queryFilterString = getQueryFilterString(f, 'tu_ngay, den_ngay, ngay3, ma_dvcs, mau_bc');
      if (g._$k != null) g._$k = [];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}

function onchange$Item(o) {
  var f = o.parentForm, s = o.field.Name, v = (s == 'tk_bac');
  var a = ['tk_so_cai','tk', 'tk_bac', 'xem_tat', 'tk_chi_tiet'];
  if ((s != 'xem_tat') && (s != 'tk_chi_tiet')) f.getItem('xem_tat').disabled = f.getItem('tk_chi_tiet').disabled = !v ;
  $common.setVisible(f.getItem('tk_1').a, s == 'tk');
  for(var i = 0; i < a.length; i++) {
    if (f.getItem(a[i]) != o) f.getItem(a[i]).checked = false;
      else f.getItem(s).checked = true;
  }

  if (s == 'tk_so_cai') {
	    setItemDisable(f.getItem('tk_so_cai'));
  }

  if (s == 'tk') {
    setItemDisable(f.getItem('tk'));
    f.getItem('tk_bac_1').value = '99';
    f.setItemValue('tk_so_cai_1', 0);
  }
  else {
    f.getItem('tk_1').value = '';
    f.getItem('ten_tk%l').value = '';
  }
  if (s == 'tk_bac') {
    setItemDisable(f.getItem('tk_bac'));
    f.getItem('xem_tat').checked = true;
    f.setItemValue('tk_so_cai_1', 0);
  }

  if (s == 'xem_tat') f.getItem('tk_bac').checked = true;
  if (s == 'tk_chi_tiet') f.getItem('tk_bac').checked = true;
  var c = f.getItemValue('tk_so_cai') ? 'tk_so_cai_1' : (f.getItemValue('tk') ? 'tk_1' : 'tk_bac_1');
  f.getItem(c).focus();
}
function setItemDisable(o) {
  var f = o.parentForm, s = o.field.Name, a = ['tk_1', 'tk_bac_1', 'tk_so_cai_1'];
  for (var i = 0; i < a.length; i++) {
    f.getItem(a[i]).disabled = ((s + '_1') != a[i]);
  }
}
function setItemVisible(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
